export function buildAIChatSystemPrompt(
  riders: RiderPerformanceProfile[],
  summary: FleetPerformanceSummary,
): string {
  const top5 = [...riders]
    .sort((a, b) => b.performanceScore - a.performanceScore)
    .slice(0, 5)
