      (r, i) =>
        `  ${i + 1}. ${r.employeeName} — ${r.totalOrders} طلب — تقييم ${r.performanceScore}/100 — ${tierLabel(r.tier)}`,
    )
    .join('\n');

  const bottom5 = [...riders]
    .sort((a, b) => a.performanceScore - b.performanceScore)
    .slice(0, 5)
    .map(
      (r, i) =>
        `  ${i + 1}. ${r.employeeName} — ${r.totalOrders} طلب — تقييم ${r.performanceScore}/100 — ${tierLabel(r.tier)}`,
    )
    .join('\n');

  const improved = [...riders]
    .filter((r) => r.growthPct > 0)
