      | 'declining'
      | 'below_target'
      | 'stable'
      | 'average';
  };
  alerts: Array<{
    alertType: PerformanceAlertType;
    severity: PerformanceSeverity;
  }>;
  salary:
    | {
        baseSalary: number;
        allowances: number;
        attendanceDeduction: number;
        advanceDeduction: number;
        externalDeduction: number;
        manualDeduction: number;
        netSalary: number;
        isApproved: boolean;
        paymentMethod?: string | null;
      }
    | null;
}

export interface OrderImportBatch {
  id: string;
  month_year: string;
  source_type: 'manual' | 'excel' | 'api';
  file_name: string | null;
  status: 'pending' | 'completed' | 'failed';
  total_rows: number;
  imported_rows: number;
  skipped_rows: number;
  error_count: number;
  error_summary: Array<{ row?: number; reason: string; details?: string }> | null;
  started_at: string;
  completed_at: string | null;
}

type GenericTableClient = {
  from: (table: string) => any;
};

const sb = supabase as unknown as GenericTableClient & typeof supabase;

export const performanceService = {
  getDashboard: async (monthYear: string): Promise<PerformanceDashboardResponse> => {
    const { data, error } = await supabase.rpc('performance_dashboard_rpc', {
      p_month_year: monthYear,
    });

    if (error) {
      throw toServiceError(error, 'performanceService.getDashboard');
    }

    return (data ?? {}) as PerformanceDashboardResponse;
  },

  getRiderProfile: async (
    employeeId: string,
    monthYear: string,
  ): Promise<RiderProfilePerformanceResponse> => {
    const { data, error } = await supabase.rpc('rider_profile_performance_rpc', {
      p_employee_id: employeeId,
      p_month_year: monthYear,
    });

    if (error) {
      throw toServiceError(error, 'performanceService.getRiderProfile');
    }

    return (data ?? {}) as RiderProfilePerformanceResponse;
  },

  upsertEmployeeTarget: async (params: {
    employeeId: string;
    monthYear: string;
    monthlyTargetOrders: number;
    dailyTargetOrders: number;
  }) => {
    const { data, error } = await sb
      .from('employee_targets')
      .upsert(
        {
          employee_id: params.employeeId,
          month_year: params.monthYear,
          monthly_target_orders: params.monthlyTargetOrders,
          daily_target_orders: params.dailyTargetOrders,
        },
        { onConflict: 'employee_id,month_year' },
      )
      .select()
      .single();

    if (error) {
      throw toServiceError(error, 'performanceService.upsertEmployeeTarget');
    }

    return data;
  },

  getImportHistory: async (monthYear: string): Promise<OrderImportBatch[]> => {
    const { data, error } = await sb
      .from('order_import_batches')
      .select(
        'id, month_year, source_type, file_name, status, total_rows, imported_rows, skipped_rows, error_count, error_summary, started_at, completed_at',
      )
      .eq('month_year', monthYear)
      .order('started_at', { ascending: false })
      .limit(8);

    if (error) {
      const message =
        error &&
        typeof error === 'object' &&
        'message' in error &&
        typeof (error as { message?: unknown }).message === 'string'
          ? (error as { message: string }).message
          : '';
      if (message.includes('order_import_batches')) {
        return [];
      }
      throw toServiceError(error, 'performanceService.getImportHistory');
    }

    return (data ?? []) as OrderImportBatch[];
  },

  deleteImportBatch: async (batchId: string) => {
    const { error } = await sb
      .from('order_import_batches')
      .delete()
      .eq('id', batchId);

    if (error) {
      throw toServiceError(error, 'performanceService.deleteImportBatch');
    }
  },

  captureSalaryMonthSnapshot: async (monthYear: string) => {
    const { data, error } = await supabase.rpc('capture_salary_month_snapshot', {
      p_month_year: monthYear,
    });

    if (error) {
      throw toServiceError(error, 'performanceService.captureSalaryMonthSnapshot');
    }

    return data;
  },
};

import { useMemo, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { Building2, Loader2, Pencil, Plus, Save, Trash2, X } from 'lucide-react';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@shared/components/ui/dialog';
import { Button } from '@shared/components/ui/button';
import { Input } from '@shared/components/ui/input';
import { useToast } from '@shared/hooks/use-toast';
import { useCommercialRecords } from '@shared/hooks/useCommercialRecords';
import { commercialRecordService } from '@services/commercialRecordService';
import { getErrorMessage } from '@services/serviceError';

type CommercialRecordsManagerProps = {
  open: boolean;
  onClose: () => void;
};

export function CommercialRecordsManager({
  open,
  onClose,
}: CommercialRecordsManagerProps) {
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const { records, isLoading, tableAvailable, refetch } = useCommercialRecords();
  const [draftName, setDraftName] = useState('');
  const [busyAction, setBusyAction] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingValue, setEditingValue] = useState('');

  const managedRecords = useMemo(
    () => records.filter((record) => record.source === 'managed'),
    [records],
  );

  const legacyRecords = useMemo(
    () => records.filter((record) => record.source === 'legacy'),
    [records],
  );

  const refreshRecords = async () => {
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ['commercial-records'] }),
      queryClient.invalidateQueries({ queryKey: ['employees'] }),
    ]);
    await refetch();
  };

  const handleCreate = async () => {
    if (!draftName.trim()) return;
    setBusyAction('create');
    try {
      await commercialRecordService.createRecord(draftName);
      setDraftName('');
      await refreshRecords();
      toast({ title: 'تمت إضافة السجل التجاري', description: draftName.trim() });
    } catch (error) {
      toast({
        title: 'تعذر إضافة السجل التجاري',
        description: getErrorMessage(error),
        variant: 'destructive',
      });
    } finally {
      setBusyAction(null);
    }
  };

  const handleSaveEdit = async () => {
    if (!editingId) return;
    const current = managedRecords.find((record) => record.id === editingId);
    if (!current) return;

    setBusyAction(`update:${editingId}`);
    try {
      await commercialRecordService.updateRecord(editingId, editingValue, current.name);
      setEditingId(null);
      setEditingValue('');
      await refreshRecords();
      toast({ title: 'تم تحديث السجل التجاري', description: editingValue.trim() });
    } catch (error) {
      toast({
        title: 'تعذر تحديث السجل التجاري',
        description: getErrorMessage(error),
        variant: 'destructive',
      });
    } finally {
      setBusyAction(null);
    }
  };

  const handleDelete = async (recordId: string, recordName: string) => {
    setBusyAction(`delete:${recordId}`);
    try {
      await commercialRecordService.deleteRecord(recordId);
      await refreshRecords();
      toast({
        title: 'تم حذف السجل التجاري من القائمة',
        description: `بقي ربط الموظفين الحاليين على القيمة النصية: ${recordName}`,
      });
    } catch (error) {
      toast({
        title: 'تعذر حذف السجل التجاري',
        description: getErrorMessage(error),
        variant: 'destructive',
      });
    } finally {
      setBusyAction(null);
    }
  };

  const canMutate = tableAvailable && busyAction == null;

  return (
    <Dialog open={open} onOpenChange={(nextOpen) => !nextOpen && onClose()}>
      <DialogContent dir="rtl" className="max-w-3xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Building2 size={18} className="text-primary" />
            إدارة السجلات التجارية
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-5">
          {!tableAvailable && (
            <div className="rounded-xl border border-destructive/30 bg-destructive/5 px-4 py-3 text-sm text-destructive">
              إدارة الإضافة والتعديل والحذف تحتاج تطبيق migration السجلات التجارية على قاعدة البيانات.
            </div>
          )}

          <div className="rounded-2xl border border-border/60 bg-muted/20 p-4">
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center">
              <Input
                value={draftName}
                onChange={(event) => setDraftName(event.target.value)}
                placeholder="اسم السجل التجاري"
                disabled={!tableAvailable || busyAction === 'create'}
              />
              <Button
                type="button"
                className="gap-2"
                onClick={handleCreate}
                disabled={!tableAvailable || !draftName.trim() || busyAction === 'create'}
              >
                {busyAction === 'create' ? <Loader2 size={14} className="animate-spin" /> : <Plus size={14} />}
                إضافة سجل
              </Button>
            </div>
            <p className="mt-2 text-xs text-muted-foreground">
              تعديل اسم السجل من هنا يحدّث أيضًا السجل النصي المرتبط بالموظفين الحاليين بنفس الاسم.
            </p>
          </div>

          <div className="grid gap-4 lg:grid-cols-[1.5fr_1fr]">
            <div className="rounded-2xl border border-border/60">
              <div className="border-b border-border/60 px-4 py-3">
                <h3 className="text-sm font-semibold text-foreground">السجلات المُدارة</h3>
                <p className="text-xs text-muted-foreground">القائمة المستخدمة في نموذج إضافة وتعديل المندوب.</p>
              </div>

              <div className="max-h-[360px] space-y-2 overflow-y-auto p-4">
                {isLoading && (
                  <div className="flex items-center justify-center gap-2 py-10 text-sm text-muted-foreground">
                    <Loader2 size={16} className="animate-spin" />
                    جاري تحميل السجلات التجارية...
                  </div>
                )}

                {!isLoading && managedRecords.length === 0 && (
                  <div className="rounded-xl border border-dashed border-border px-4 py-8 text-center text-sm text-muted-foreground">
                    لا توجد سجلات مُدارة بعد.
                  </div>
                )}

                {!isLoading && managedRecords.map((record) => {
                  const isEditing = editingId === record.id;
                  const rowBusy = busyAction === `update:${record.id}` || busyAction === `delete:${record.id}`;

                  return (
                    <div
                      key={record.id}
                      className="rounded-xl border border-border/60 bg-card px-4 py-3"
                    >
                      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
                        <div className="min-w-0 flex-1">
                          {isEditing ? (
                            <Input
                              value={editingValue}
                              onChange={(event) => setEditingValue(event.target.value)}
                              disabled={rowBusy}
                              autoFocus
                            />
                          ) : (
                            <div className="flex items-center gap-2">
                              <span className="truncate font-medium text-foreground">{record.name}</span>
                              <span className="rounded-full bg-primary/10 px-2 py-0.5 text-[11px] font-semibold text-primary">
                                {record.usage_count} مندوب
                              </span>
                            </div>
                          )}
                        </div>

                        <div className="flex items-center gap-2">
                          {isEditing ? (
                            <>
                              <Button
                                type="button"
                                size="sm"
                                className="gap-1.5"
                                onClick={handleSaveEdit}
                                disabled={rowBusy || !editingValue.trim()}
                              >
                                {rowBusy ? <Loader2 size={13} className="animate-spin" /> : <Save size={13} />}
                                حفظ
                              </Button>
                              <Button
                                type="button"
                                size="sm"
                                variant="outline"
                                onClick={() => {
                                  setEditingId(null);
                                  setEditingValue('');
                                }}
                                disabled={rowBusy}
                              >
                                إلغاء
                              </Button>
                            </>
                          ) : (
                            <>
                              <Button
                                type="button"
                                size="sm"
                                variant="outline"
                                className="gap-1.5"
                                onClick={() => {
                                  setEditingId(record.id);
                                  setEditingValue(record.name);
                                }}
                                disabled={!canMutate}
                              >
                                <Pencil size={13} />
                                تعديل
                              </Button>
                              <Button
                                type="button"
                                size="sm"
                                variant="destructive"
                                className="gap-1.5"
                                onClick={() => void handleDelete(record.id!, record.name)}
                                disabled={!canMutate}
                              >
                                {rowBusy ? <Loader2 size={13} className="animate-spin" /> : <Trash2 size={13} />}
                                حذف
                              </Button>
                            </>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="rounded-2xl border border-border/60">
              <div className="border-b border-border/60 px-4 py-3">
                <h3 className="text-sm font-semibold text-foreground">قيم مستخدمة حاليًا</h3>
                <p className="text-xs text-muted-foreground">قيم موجودة على الموظفين حتى لو لم تُدار بعد من الجدول الجديد.</p>
              </div>

              <div className="max-h-[360px] space-y-2 overflow-y-auto p-4">
                {records.length === 0 && !isLoading && (
                  <div className="rounded-xl border border-dashed border-border px-4 py-8 text-center text-sm text-muted-foreground">
                    لا توجد قيَم مستخدمة حاليًا.
                  </div>
                )}

                {records.map((record) => (
                  <div
                    key={`${record.source}-${record.id ?? record.name}`}
                    className="rounded-xl border border-border/60 bg-card px-4 py-3"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="min-w-0">
                        <p className="truncate text-sm font-medium text-foreground">{record.name}</p>
                        <p className="text-xs text-muted-foreground">
                          {record.source === 'managed' ? 'مُدار من القائمة' : 'موجود على الموظفين فقط'}
                        </p>
                      </div>
                      <span className="rounded-full bg-muted px-2 py-0.5 text-[11px] font-semibold text-muted-foreground">
                        {record.usage_count}
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="flex justify-end">
            <Button type="button" variant="outline" onClick={onClose} className="gap-2">
              <X size={14} />
              إغلاق
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

export default CommercialRecordsManager;
